import com.smartquiz.config.DBConnection; import java.sql.*; public class GetJoinCode { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection(); Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT name, join_code FROM classes LIMIT 1")) { if (rs.next()) { System.out.println("Class: " + rs.getString("name") + ", Code: " + rs.getString("join_code")); } } } }
